// Validate incoming payload
const body = $input.first().json.body;

const required = ['user_id', 'user_email', 'input_type', 'input_content', 'base_package', 'credits_cost'];
const missing = required.filter(f => !body[f]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

const validPackages = ['essentials', 'preacher', 'master'];
if (!validPackages.includes(body.base_package)) {
  throw new Error(`Invalid base_package: ${body.base_package}`);
}

const validInputTypes = ['passage', 'topic', 'youtube', 'audio', 'pdf', 'notes'];
if (!validInputTypes.includes(body.input_type)) {
  throw new Error(`Invalid input_type: ${body.input_type}`);
}

// Set defaults for optional fields
return [{
  json: {
    user_id: body.user_id,
    user_email: body.user_email,
    input_type: body.input_type,
    input_content: body.input_content,
    base_package: body.base_package,
    credits_cost: body.credits_cost,
    doctrinal_position: body.doctrinal_position || 'Mid-Acts Dispensational',
    bible_translation: body.bible_translation || 'KJV',
    audience: body.audience || 'Sunday Morning - Mixed',
    sermon_style: body.sermon_style || 'Expository (Verse-by-Verse)',
    desired_length: body.desired_length || 30,
    tone: body.tone || 'Pastoral / Encouraging',
    focus: body.focus || 'Application Focused',
    addons: body.addons || [],
    project_id: body.project_id || null,
    attempt: 1
  }
}];

// Pass through content as-is for passage, topic, notes, pdf, audio
const data = $('Validate & Normalize Input').item.json;
return [{ json: { processed_content: data.input_content } }];

// Merge the processed content back with original request data
const validated = $('Validate & Normalize Input').item.json;

// Get content from whichever branch ran
let processed_content = '';
try {
  processed_content = $('Fetch YouTube Transcript').item.json.content || $('Fetch YouTube Transcript').item.json.text || '';
} catch(e) {
  try {
    processed_content = $('Pass Content Through').item.json.processed_content;
  } catch(e2) {
    processed_content = validated.input_content;
  }
}

return [{
  json: {
    ...validated,
    processed_content
  }
}];

// Build the system prompt based on theological settings
const data = $input.first().json;

const systemPrompt = `You are an expert biblical theologian and sermon writer operating within a ${data.doctrinal_position} theological framework.

THEOLOGICAL PARAMETERS:
- Doctrinal Position: ${data.doctrinal_position}
- Bible Translation: ${data.bible_translation}
- All Scripture references must use the ${data.bible_translation}
- Dispensational awareness is critical: rightly divide the Word of Truth (2 Timothy 2:15)
- Paul's epistles (Romans through Philemon) are the primary doctrinal source for the Body of Christ today
- Grace doctrine: salvation by grace through faith alone, apart from works

SERMON PARAMETERS:
- Audience: ${data.audience}
- Style: ${data.sermon_style}
- Desired Length: ${data.desired_length} minutes (approx ${data.desired_length * 130} words for spoken delivery)
- Tone: ${data.tone}
- Focus: ${data.focus}

OUTPUT RULES:
- Always cite Scripture with book, chapter, and verse
- Stay doctrinally consistent with Mid-Acts dispensationalism throughout
- Do not mix kingdom gospel (Matthew-Acts 8) with grace gospel (Acts 9 onward)
- Applications should be practical and relevant to a modern congregation
- Write in clear, accessible language appropriate for ${data.audience}`;

return [{ json: { ...data, system_prompt: systemPrompt } }];

