// Parse whichever Gemini node ran and normalize output
let rawContent = '';
let packageType = '';
let sourceData = {};

try {
  rawContent = $('Generate - Essentials Package').item.json.text || $('Generate - Essentials Package').item.json.content || '';
  packageType = 'essentials';
  sourceData = $('Build System Prompt').item.json;
} catch(e) {}

if (!rawContent) {
  try {
    rawContent = $('Generate - Preacher Package').item.json.text || $('Generate - Preacher Package').item.json.content || '';
    packageType = 'preacher';
    sourceData = $('Build System Prompt').item.json;
  } catch(e) {}
}

if (!rawContent) {
  try {
    rawContent = $('Generate - Master Sermon Package').item.json.text || $('Generate - Master Sermon Package').item.json.content || '';
    packageType = 'master';
    sourceData = $('Build System Prompt').item.json;
  } catch(e) {}
}

if (!rawContent) {
  throw new Error('No content returned from any Gemini generation node');
}

// Strip markdown fences if present
const cleaned = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let sermonJson;
try {
  sermonJson = JSON.parse(cleaned);
} catch(e) {
  throw new Error(`Failed to parse Gemini JSON output: ${e.message}. Raw: ${cleaned.substring(0, 200)}`);
}

return [{
  json: {
    ...sourceData,
    package_type: packageType,
    sermon: sermonJson,
    generated_at: new Date().toISOString()
  }
}];

// Build HTML email body with the full sermon
const data = $input.first().json;
const sermon = data.sermon;

let bodyHtml = `
<div style="font-family: Georgia, serif; max-width: 700px; margin: 0 auto; color: #2C2C2A;">
  <div style="background: #7F77DD; padding: 24px 32px; border-radius: 12px 12px 0 0;">
    <h1 style="color: white; margin: 0; font-size: 24px;">✚ GraceTools</h1>
    <p style="color: rgba(255,255,255,0.8); margin: 8px 0 0;">Your sermon is ready</p>
  </div>

  <div style="background: white; padding: 32px; border: 1px solid #E0E0E0;">
    <h2 style="font-size: 28px; color: #1a1a1a; margin-bottom: 8px;">${sermon.title || 'Untitled Sermon'}</h2>
    <p style="color: #7F77DD; font-weight: 600; margin-bottom: 24px;">${sermon.scripture_reference || ''} | ${data.bible_translation} | ${data.doctrinal_position}</p>

    <div style="background: #F5F3FF; border-left: 4px solid #7F77DD; padding: 16px 20px; border-radius: 0 8px 8px 0; margin-bottom: 24px;">
      <p style="font-weight: 700; color: #534AB7; margin: 0 0 4px; font-size: 12px; text-transform: uppercase; letter-spacing: 1px;">Big Idea</p>
      <p style="color: #1a1a1a; margin: 0; font-size: 16px; font-style: italic;">${sermon.big_idea || ''}</p>
    </div>
`;

// Introduction (if preacher or master)
if (sermon.introduction) {
  bodyHtml += `
    <h3 style="color: #534AB7; border-bottom: 1px solid #E0E0E0; padding-bottom: 8px;">Introduction</h3>
    <p style="line-height: 1.8; color: #444;">${sermon.introduction}</p>
  `;
}

// Main Points
if (sermon.main_points && sermon.main_points.length > 0) {
  bodyHtml += `<h3 style="color: #534AB7; border-bottom: 1px solid #E0E0E0; padding-bottom: 8px; margin-top: 28px;">Main Points</h3>`;
  sermon.main_points.forEach((pt, i) => {
    bodyHtml += `
      <div style="margin-bottom: 20px; padding: 16px; background: #FAFAFA; border-radius: 8px; border: 1px solid #E0E0E0;">
        <h4 style="color: #1a1a1a; margin: 0 0 8px;">${i+1}. ${pt.point}</h4>
        <p style="color: #666; margin: 0 0 8px; line-height: 1.7;">${pt.explanation}</p>
        ${pt.scripture ? `<p style="color: #7F77DD; font-size: 13px; font-style: italic; margin: 0 0 6px;">📖 ${pt.scripture}</p>` : ''}
        ${pt.application ? `<p style="color: #444; font-size: 13px; margin: 0;"><strong>Application:</strong> ${pt.application}</p>` : ''}
      </div>
    `;
  });
}

// Verse by Verse (master only)
if (sermon.verse_by_verse_commentary && sermon.verse_by_verse_commentary.length > 0) {
  bodyHtml += `<h3 style="color: #534AB7; border-bottom: 1px solid #E0E0E0; padding-bottom: 8px; margin-top: 28px;">Verse-by-Verse Commentary</h3>`;
  sermon.verse_by_verse_commentary.forEach(v => {
    bodyHtml += `
      <div style="margin-bottom: 16px;">
        <p style="font-weight: 700; color: #534AB7; margin: 0 0 4px;">${v.verse}</p>
        <p style="color: #444; line-height: 1.7; margin: 0;">${v.commentary}</p>
      </div>
    `;
  });
}

// Conclusion
if (sermon.conclusion) {
  bodyHtml += `
    <h3 style="color: #534AB7; border-bottom: 1px solid #E0E0E0; padding-bottom: 8px; margin-top: 28px;">Conclusion</h3>
    <p style="line-height: 1.8; color: #444;">${sermon.conclusion}</p>
  `;
}

// Key Takeaways
if (sermon.key_takeaways && sermon.key_takeaways.length > 0) {
  bodyHtml += `
    <h3 style="color: #534AB7; border-bottom: 1px solid #E0E0E0; padding-bottom: 8px; margin-top: 28px;">Key Takeaways</h3>
    <ul style="color: #444; line-height: 2;">
      ${sermon.key_takeaways.map(t => `<li>${t}</li>`).join('')}
    </ul>
  `;
}

// Discussion Questions (master only)
if (sermon.discussion_questions && sermon.discussion_questions.length > 0) {
  bodyHtml += `
    <h3 style="color: #534AB7; border-bottom: 1px solid #E0E0E0; padding-bottom: 8px; margin-top: 28px;">Discussion Questions</h3>
    <ol style="color: #444; line-height: 2;">
      ${sermon.discussion_questions.map(q => `<li>${q}</li>`).join('')}
    </ol>
  `;
}

// Children's Message (master only)
if (sermon.childrens_message) {
  bodyHtml += `
    <h3 style="color: #534AB7; border-bottom: 1px solid #E0E0E0; padding-bottom: 8px; margin-top: 28px;">Children's Message</h3>
    <p style="line-height: 1.8; color: #444;">${sermon.childrens_message}</p>
  `;
}

// Object Lesson (master only)
if (sermon.object_lesson) {
  bodyHtml += `
    <div style="background: #F0F9F4; border: 1px solid #9FE1CB; border-radius: 8px; padding: 16px; margin-top: 20px;">
      <p style="font-weight: 700; color: #0F6E56; margin: 0 0 8px;">Object Lesson: ${sermon.object_lesson.object}</p>
      <p style="color: #444; margin: 0; line-height: 1.7;">${sermon.object_lesson.lesson}</p>
    </div>
  `;
}

bodyHtml += `
    <div style="margin-top: 32px; padding: 16px; background: #F5F3FF; border-radius: 8px; text-align: center;">
      <p style="color: #534AB7; font-size: 13px; margin: 0;">Estimated speaking time: ${sermon.estimated_speaking_time || data.desired_length + ' minutes'}</p>
      <p style="color: #888; font-size: 12px; margin: 8px 0 0;">Generated by GraceTools | ${data.doctrinal_position} | ${data.bible_translation}</p>
    </div>
  </div>

  <div style="background: #F5F3FF; padding: 16px 32px; border-radius: 0 0 12px 12px; text-align: center;">
    <p style="color: #888; font-size: 12px; margin: 0;">© GraceTools. Built for pastors.</p>
  </div>
</div>
`;

return [{
  json: {
    ...data,
    email_html: bodyHtml,
    email_subject: `Your Sermon is Ready: ${sermon.title || 'Untitled'}`
  }
}];

// ERROR HANDLER - runs when any node above fails
// Captures error context and passes to retry/refund flow
const errorData = $input.first().json;
const validated = $('Validate & Normalize Input').item.json;

return [{
  json: {
    user_id: validated.user_id || 'unknown',
    user_email: validated.user_email || 'unknown',
    project_id: validated.project_id || null,
    credits_cost: validated.credits_cost || 0,
    attempt: validated.attempt || 1,
    error_message: errorData.error?.message || 'Unknown error during generation',
    failed_at: new Date().toISOString()
  }
}];
